
"use client";

import { useState, useEffect } from "react";
import Image from 'next/image';
import Link from 'next/link';
import {
  ArrowLeft,
  Monitor,
  User as UserIcon,
  Clock,
  Wifi,
  WifiOff
} from 'lucide-react';
import { useParams } from "next/navigation";
import { getLabsAction, getPcsAction, getLabRequestsAction, getUsersAction } from "@/app/actions/dbActions";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Pc, Lab, LabRequest, User } from "@/utils/storage";
import { toast } from "sonner";
import { Badge } from "@/components/ui/badge";
import AdminSidebar from "@/components/admin/AdminSidebar";

export default function LabDetailPage() {
    const params = useParams();
    const labId = params.labId as string;
    const [lab, setLab] = useState<Lab | null>(null);
    const [pcs, setPcs] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchData = async () => {
            if (!labId) return;
            setLoading(true);
            try {
                const allLabs = await getLabsAction();
                const currentLab = allLabs.find(l => l.id === labId);
                setLab(currentLab || null);

                if (!currentLab) {
                    toast.error("Lab not found.");
                    return;
                }

                const allPcs = await getPcsAction();
                const labPcs = allPcs.filter(pc => pc.labId === labId);

                const requests = await getLabRequestsAction();
                const users = await getUsersAction();
                const now = new Date();

                const pcsWithStatus = labPcs.map(pc => {
                    const activeRequest = requests.find(r => 
                        r.pcId === pc.id && 
                        r.status === 'approved' &&
                        now >= new Date(r.startTime) &&
                        now <= new Date(r.endTime)
                    );
                    
                    const user = activeRequest ? users.find(u => u.id === activeRequest.studentId) : null;

                    return {
                        ...pc,
                        status: activeRequest ? 'occupied' : 'available',
                        currentUser: user,
                        currentRequest: activeRequest
                    };
                });
                
                setPcs(pcsWithStatus.sort((a,b) => parseInt(a.pcNumber) - parseInt(b.pcNumber)));
            } catch (e) {
                console.error(e);
                toast.error("Failed to load lab details.");
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, [labId]);

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col">
            <header className="bg-primary shadow-lg sticky top-0 z-20">
                <div className="mx-auto px-8 h-16 flex items-center">
                    <Image src="/logo.png" alt="AMA Student Portal" width={150} height={38} priority />
                </div>
            </header>
            <div className="flex flex-1">
                <AdminSidebar />
                <main className="flex-1 p-8 overflow-y-auto">
                    <div className="mb-8">
                        <Button asChild variant="ghost" className="mb-4">
                            <Link href="/admin/labs"><ArrowLeft className="mr-2 h-4 w-4" /> Back to Labs</Link>
                        </Button>
                        <h1 className="text-3xl font-bold text-gray-800">{lab?.name}</h1>
                        <p className="text-muted-foreground">Real-time PC status overview</p>
                    </div>

                    {loading ? <p>Loading PCs...</p> : (
                        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 xl:grid-cols-8 gap-4">
                            {pcs.map(pc => (
                                <Card key={pc.id} className={`shadow-sm hover:shadow-lg transition-shadow border-2 ${pc.status === 'occupied' ? 'border-red-200 bg-red-50/50' : 'border-green-200 bg-green-50/50'}`}>
                                    <CardHeader className="flex flex-row items-center justify-between pb-2">
                                        <CardTitle className="text-sm font-medium flex items-center gap-2">
                                            <Monitor className={`h-4 w-4 ${pc.status === 'occupied' ? 'text-red-500' : 'text-green-600'}`} />
                                            PC #{pc.pcNumber}
                                        </CardTitle>
                                        {pc.status === 'occupied' ? <WifiOff className="h-4 w-4 text-red-500"/> : <Wifi className="h-4 w-4 text-green-600"/> }
                                    </CardHeader>
                                    <CardContent>
                                        <div className="text-lg font-bold capitalize">
                                            {pc.status}
                                        </div>
                                        {pc.status === 'occupied' && pc.currentUser && (
                                            <div className="mt-2 pt-2 border-t border-red-100 text-xs text-red-900">
                                                <p className="font-bold truncate">{pc.currentUser.name}</p>
                                                <p className="text-red-900/70">{pc.currentUser.id}</p>
                                                <p className="flex items-center gap-1 mt-1 text-red-900/70">
                                                    <Clock className="h-3 w-3"/> 
                                                    {new Date(pc.currentRequest.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                                </p>
                                            </div>
                                        )}
                                    </CardContent>
                                </Card>
                            ))}
                        </div>
                    )}
                </main>
            </div>
        </div>
    );
}
